var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임</color> 승전, 보름 뒤","JPN":"<color=#ffd34c>クリフォトゲーム</color>勝利、2週間後","ENG":"<color=#ffd34c>Qliphoth Game</color> victory, 2 weeks later","TWN":"<color=#ffd34c>逆卡巴拉遊戲</color>勝利，半個月後","SCN":"<color=#ffd34c>神圣战役</color>胜利，半个月后","DEU":"<color=#ffd34c>Qliphoth Game</color> victory, 2 weeks later","FRA":"<color=#ffd34c>Qliphoth Game</color> victory, 2 weeks later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"이야~ 프론트베이는 오늘도 햇볕이 따갑네요.","JPN":"いや～フロントベイは今日も日差しが熱いですね。","ENG":"Wow! The sun in Front Bay is hot as ever.","TWN":"哎呀～前灣今天的陽光也很刺眼呢。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"오늘은 이곳 프론트베이에서 화보 촬영을 진행하고 계신 스완 양을 어렵게 모셨답니다.","JPN":"本日はこのフロントベイで写真集の撮影を行っているスワンさんに、インタビューに応じていただきました。","ENG":"Today, we are meeting with Miss Swan who is in Front Bay for a photoshoot.","TWN":"今天我們在這裡難得邀請到正在進行拍攝的史旺。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"안녕하세요, 스완 양.","JPN":"こんにちは、スワンさん。","ENG":"Hello, Miss Swan.","TWN":"你好，史旺。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"정말 오래간만에 다시 작품 활동을 시작하셨는데 소감 한마디 들을 수 있을까요?","JPN":"本当に久しぶりに映像作品への出演を再開されましたが、感想を一言お願いします。","ENG":"You've returned to work after a long break. May I ask how you feel about it?","TWN":"你好像很久沒有重新開始創作了，能聽聽你的感想嗎？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"영화가 아닌 드라마는 처음일 텐데, 벌써부터 대중들의 반응이 뜨겁던데요?","JPN":"映画ではなくドラマですよね。ドラマは初めてだと聞きましたが、反響がすごいですね。","ENG":"It's your first time away from the silver screen and doing a drama series, but the public's reaction is already so enthusiastic.","TWN":"這應該是你第一次離開銀幕，嘗試拍攝電視劇吧？觀眾們的反應已經非常熱烈了呢？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 글쎄요. 원래 무대 출신이라 저에게 있어서도 이번 시도는 도전이랍니다.","JPN":"ふふ、そうですね。もともと舞台出身ですから、私にとっても今回の作品は挑戦なんです。","ENG":"Haha, well. Since my background comes from doing stages, I think this will be like a challenge to myself.","TWN":"呵呵，怎麼說呢。畢竟我是舞台出身，這次嘗試對我來說也是一種挑戰。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 이야기가 단막극이 아닌, 연속극이 된다는 게 말이죠.","JPN":"短編ではなくシリーズ物に出演するのは今回が初めてですから。","ENG":"It would mean that my story will not be a one-act play, but a serial drama.","TWN":"我的故事不再是獨幕劇，而是連續劇了。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아하, 사람들은 스완 양을 영화 배우라고 알고 있는데, 원래 극단 출신이셨군요.","JPN":"ほお、スワンさんは映画の女優として知られていますが、劇団出身だったんですね。","ENG":"A-ha. The people normally know you as a movie star, but you were originally a stage actress.","TWN":"啊哈，人們都以為史旺是電影演員，原來你是劇團出身的啊。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 그래서 긴장을 많이 했는데 스태프분들께서 도와주셔서 편하게 연기할 수 있었죠.","JPN":"はい、それでとても緊張したんですが、スタッフの皆さんに助けられて、リラックスして演じることができました。","ENG":"Yes. I used to be nervous whenever I was up on stage, but the staff helped me so that I could act comfortably.","TWN":"是的，當時的我還很緊張，但工作人員幫了我很多，讓我能夠安心表演。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"의외네요. 스완 양 같은 천재도 긴장이라는 걸 하다니.","JPN":"スワンさんのような天才も緊張するんですか？　意外ですね。","ENG":"That's surprising to hear. A genius like you getting nervous.","TWN":"真意外，像史旺這樣的天才也會緊張。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대 위에 서면 항상 설레고 긴장되는 건 누구나 똑같은 걸요.","JPN":"舞台に立つといつもドキドキして緊張するのは、私でも同じなんです。","ENG":"Everyone feels excited and nervous whenever they're on stage.","TWN":"站在舞台上總是既興奮又緊張，這對每個人來說都是一樣的。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 절 지켜봐 주시는 팬분들을 실망시킬 수는 없으니까요.","JPN":"でも見守ってくださるファンの皆さんをがっかりさせる訳にはいきませんから。","ENG":"But I can't disappoint my fans.","TWN":"但是我不能讓支持我的粉絲們失望。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언제나 우아하고, 아름답게 보이려고 노력하고 있답니다.","JPN":"常に優雅で、美しく見えるように努力しています。","ENG":"I try my best to look elegant and graceful.","TWN":"我一直在努力讓自己看起來優雅而美麗。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"역시 프로의 마음가짐은 무언가 다르네요.","JPN":"やっぱりプロの心構えはすごいですね！","ENG":"A professional's mindset is different, I see.","TWN":"果然，專業人士的心態就是不一樣。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그러고 보니, 이번 작품은 본인이 직접 각본을 구상했다고 하던데요?","JPN":"そういえば、今回の作品はご自身で脚本を書かれたとか？","ENG":"Come to think of it, didn't you say you wrote the script?","TWN":"說起來，這次的作品聽說是你親自構思的劇本？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네. 이번 작품은 처음부터 끝까지 제가 직접 관여하고 있습니다.","JPN":"はい、今回の作品は最初から最後まで私が直接関わらせていただいています。","ENG":"Yes. I was involved in this work from start to finish.","TWN":"是的。這次的作品從頭到尾都有我親自參與。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본뿐만이 아니라, 프로듀싱과 캐스팅, 로케이션 섭외 및 조연도 한자리 맡게 되었죠.","JPN":"脚本だけでなくプロデュースやキャスティング、ロケ地の手配、あと脇役を一つ担当しています。","ENG":"It's not just the script, but I was also responsible for the producing, casting, location selecting, and supporting roles.","TWN":"不僅僅是劇本，這次我還嘗試了製作、選角、場地安排，以及承擔了一些配角的飾演工作。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"조연이라고요?","JPN":"脇役ですか？","ENG":"Supporting roles?","TWN":"配角？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네. 사실, 전 선역보다는 악역을 선호하는 편이라서요.","JPN":"はい。実は私、悪役のほうが好みなんです。","ENG":"Yes. I tend to prefer villainous roles over good ones.","TWN":"是的。其實，我更喜歡反派角色。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 편이 팬분들께 좀 더 다채로운 연기를 보여드릴 수 있으니까요.","JPN":"その方が、ファンの皆さんに色んな演技をお見せすることができますしね。","ENG":"Because I'm able to show my fans a more diverse acting.","TWN":"這樣可以向粉絲們展示更多樣的演技。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그러고보니 아침 드라마로 기획된 이야기치고 꽤 진지하다는 이야기를 들었는데요","JPN":"そういえば朝ドラとして企画された内容にしては、結構重いストーリーだと聞きました。","ENG":"I heard the story for this morning series is quite serious.","TWN":"這麼說來，我聽說這部作為晨間劇播出的作品，故事策劃蠻挺嚴肅的呢？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 전세계 동시 송출이라 방영 시간대는 어디서 시청하시는지에 따라 다르겠죠.","JPN":"まあ、全世界同時配信なので時間帯は地域によって違いますからね。","ENG":"Well, it will be broadcast simultaneously all around the world, so I think it will feel different depending on where you watch it.","TWN":"這個嘛，由於全球同步播出，播放時間會因你所在的地區而異。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"작품이 정말로 진정성을 갖는다면, 방영 시간대는 크게 의미가 없지 않을까요?","JPN":"作品の本気が伝われば、放送時間帯はあまり関係ないんじゃないでしょうか。","ENG":"If we all put our 100 percent into the series, I don't think when it is aired will have a great significance.","TWN":"如果作品真的有誠意，播放時間應該沒那麼重要吧？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"하하, 아티스트의 귀감이라고 할 수 있는 도전적인 발언이네요.","JPN":"はは、アーティストの鑑ともいえる挑戦的な発言ですね。","ENG":"Haha. That's a bold statement coming from a role model artist.","TWN":"哈哈，這真是藝術家的典範，充滿挑戰性的發言啊。"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그래서 작품에 관해 한 마디 들을 수 있을까요?","JPN":"作品についても一言、コメントをいただけるでしょうか。","ENG":"Could we get your comment about the series?","TWN":"那麼，可以聽你談談作品嗎？"},"stage":{"bg":"FRONTBAY_IN","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};